var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"휴우, 이런 자리는 긴장되네요.","JPN":"ふう、このような席は緊張しますね。","ENG":"Whew... I'm so nervous.","TWN":"呼，這種場合真緊張。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"세례나 위병식은 해봤지만 높은 분을 독대하는 건 처음이거든요.","JPN":"洗礼や衛兵式は経験しましたが、偉い方と単独で面談するのは初めてなんです。","ENG":"I've done baptizes and guard ceremonies, but it's my first time in a one-on-one meeting with the higher ups.","TWN":"雖然參加過洗禮和衛兵儀式，但這還是我第一次單獨見面老闆。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"이곳에서의 생활이요? 당연히 마음에 들죠! 추위에 떨거나 굶을 걱정도 없잖아요?","JPN":"ここでの生活ですか？　当然気に入っています！　寒さに震えたり飢える心配もありませんから。","ENG":"How am I adjusting here? Very well! I don't have to worry about being cold and going hungry!","TWN":"這裡的生活嗎？當然喜歡啦！不用擔心受凍或挨餓，不是嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"의지가 되는 분들도 많이 만났고, 뭣보다 겨울에도 포도를 먹을 수 있는 곳이니까요!","JPN":"頼りになる方ともたくさん出会えて、何より冬でもブドウが食べられますから！","ENG":"I also met a lot of people I can rely on, and most of all, I can eat grapes in winter!","TWN":"還遇到很多可靠的人，最重要的是，這裡冬天也能吃到葡萄！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"이런 곳이라면 평생 지내는 것도 괜찮을…","JPN":"これなら一生ここで過ごすのもいい…… ","ENG":"I think it'll be nice to stay here forever–","TWN":"如果是這樣的地方，住一輩子也不錯…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"앗.","JPN":"あっ。","ENG":"Oh.","TWN":"哎呀。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"죄송해요. 평생이라니… 깜짝 놀라셨죠?","JPN":"すみません。一生だなんて……びっくりしましたよね？","ENG":"Sorry. Were you surprised when I said forever...?","TWN":"抱歉，說要住一輩子…有嚇到老闆吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"딱히 부담 드리려던 건 아니었어요. 어디에서 온 지도 모르는 이방인을 잠시나마 받아 주신 것만으로도 감사한 걸요.","JPN":"そういう意味じゃないんです。どこから来たかもわからない異邦人を短い間でも受け入れてくださっただけでありがたいですから。","ENG":"I wasn't trying to burden you. I'm just grateful that you allowed a wandering outsider like me to stay here for a while.","TWN":"我並不是想給老闆壓力。能暫時接納一個來歷不明的外地人，我已經很心存感激。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"네…?","JPN":"え……？","ENG":"Huh...?","TWN":"什麼…？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"정말인가요? 여기 계속 머물러도 된다고요?","JPN":"本当ですか？　ずっとここに泊まってもいいんですか？","ENG":"Really? I can stay as long as I like?","TWN":"真的嗎？我真的可以繼續留在這裡？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"게다가 이전보다 더 신뢰하는 사이가 되고 싶다니…! 여기서 더 나아가면 저희는 대체 어떤 사이가 되는 거죠?!","JPN":"そのうえ、前よりもっと信頼できる仲になりたいだなんて……！　これ以上二人の仲が深まれば、私たちいったいどうなるんですか！？","ENG":"And you want to create a trusting relationship with me...?! What will we be if our relationship develops even further from here?!","TWN":"而且想要比以前更信任我…！再進一步的話，我們會變成什麼樣的關係…？！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"아… 그렇죠? 변함없이 사장과 직원의 사이인 거죠?","JPN":"あ……そうですよね？　変わらず社長と職員の関係ですよね？","ENG":"Oh... right? We're still an employee and a boss.","TWN":"那個…我們還會是員工和老闆，對吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"아, 아녜요. 방금 말은 잊어주세요. 저도 참, 혼자 무슨 부끄러운 생각을 한 거람?","JPN":"あ、違います。今の言葉は忘れてください。私ったら、一人で何を考えていたんでしょう？","ENG":"N-never mind. Forget what I just said. I can't believe I was imagining something else...","TWN":"呃，不，不是的。剛才的話請忘掉。我真是，自己在胡思亂想什麼呢……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"저기…! 저도 한 가지 조건이 있는데요!","JPN":"あの……！　私も一つ条件があります！","ENG":"Um...! I also have a request!","TWN":"嗯…！那麼我也有一個條件！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"사장님이란 표현은 역시 딱딱하다고 생각하거든요.","JPN":"社長という表現はやっぱり堅苦しいと思うんです。","ENG":"I think that calling you Boss feels a bit cold to me.","TWN":"我覺得叫老闆有點太生疏。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"이름이 불편하다면… 앞으로 <color=#ffd34c>당신</color>이라고 불러도 되나요?","JPN":"名前で呼ばれるのが嫌なら……これから<color=#ffd34c>あなた</color>と呼んでもいいですか？","ENG":"If you think my calling your name is too much... could I call you, <color=#ffd34c>dear</color>?","TWN":"如果叫名字不方便…以後可以直接稱呼<color=#ffd34c>你</color>嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};